arguments.file_text:
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.ShippedDate)
            .Select(s => s.ToDto())
            .ToListAsync();
    }

    public async Task<List<ShipmentDto>> GetShipmentsForCustomerAsync(string email)
    {
        return await db.Shipments
            .Where(s => s.CustomerEmail == email)
            .OrderByDescending(s => s.ShippedDate)
            .Select(s => s.ToDto())
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment?.ToDto();
    }

    public async Task<bool> UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is null) return false;

        shipment.Status = newStatus;
        await db.SaveChangesAsync();
        return true;
    }
}

using Microsoft.AspNetCore.Identity;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Data;

public static class SeedData
{
    public static async Task InitializeAsync(IServiceProvider services)
    {
        using var scope = services.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        var userManager = scope.ServiceProvider.GetRequiredService<UserManager<ApplicationUser>>();
        var roleManager = scope.ServiceProvider.GetRequiredService<RoleManager<IdentityRole>>();

        await db.Database.EnsureCreatedAsync();

        // Create roles
        foreach (var role in new[] { "Dispatcher", "Customer" })
        {
            if (!await roleManager.RoleExistsAsync(role))
                await roleManager.CreateAsync(new IdentityRole(role));
        }

        // Create dispatcher user
        if (await userManager.FindByEmailAsync("dispatcher@shiptrack.com") is null)
        {
            var dispatcher = new ApplicationUser
            {
                UserName = "dispatcher@shiptrack.com",
                Email = "dispatcher@shiptrack.com",
                EmailConfirmed = true
            };
            await userManager.CreateAsync(dispatcher, "Dispatch1!");
            await userManager.AddToRoleAsync(dispatcher, "Dispatcher");
        }

        // Create customer user
        if (await userManager.FindByEmailAsync("customer@example.com") is null)
        {
            var customer = new ApplicationUser
            {
                UserName = "customer@example.com",
                Email = "customer@example.com",
                EmailConfirmed = true
            };
            await userManager.CreateAsync(customer, "Customer1!");
            await userManager.AddToRoleAsync(customer, "Customer");
        }

        // Seed shipments
        if (!db.Shipments.Any())
        {
            var now = DateTime.UtcNow;
            db.Shipments.AddRange(
                new Shipment
                {
                    TrackingNumber = "SHP-10001",
                    Origin = "New York, NY",
                    Destination = "Los Angeles, CA",
                    Status = ShipmentStatus.InTransit,
                    ShippedDate = now.AddDays(-3),
                    EstimatedDelivery = now.AddDays(2),
                    CustomerEmail = "customer@example.com",
                    Description = "Electronics — 2 pallets"
                },
                new Shipment
                {
                    TrackingNumber = "SHP-10002",
                    Origin = "Chicago, IL",
                    Destination = "Miami, FL",
                    Status = ShipmentStatus.Pending,
                    ShippedDate = now,
                    EstimatedDelivery = now.AddDays(5),
                    CustomerEmail = "customer@example.com",
                    Description = "Furniture — 1 container"
                },
                new Shipment
                {
                    TrackingNumber = "SHP-10003",
                    Origin = "Seattle, WA",
                    Destination = "Denver, CO",
                    Status = ShipmentStatus.Delivered,
                    ShippedDate = now.AddDays(-7),
                    EstimatedDelivery = now.AddDays(-2),
                    CustomerEmail = "jane.doe@example.com",
                    Description = "Medical supplies"
                },
                new Shipment
                {
                    TrackingNumber = "SHP-10004",
                    Origin = "Houston, TX",
                    Destination = "Atlanta, GA",
                    Status = ShipmentStatus.OutForDelivery,
                    ShippedDate = now.AddDays(-2),
                    EstimatedDelivery = now,
                    CustomerEmail = "customer@example.com",
                    Description = "Auto parts — fragile"
                },
                new Shipment
                {
                    TrackingNumber = "SHP-10005",
                    Origin = "Boston, MA",
                    Destination = "Phoenix, AZ",
                    Status = ShipmentStatus.Delayed,
                    ShippedDate = now.AddDays(-5),
                    EstimatedDelivery = now.AddDays(3),
                    CustomerEmail = "bob.smith@example.com",
                    Description = "Clothing — 3 boxes"
                }
            );
            await db.SaveChangesAsync();
        }
    }
}

using Microsoft.AspNetCore.Mvc;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentApi(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (IShipmentService service) =>
            Results.Ok(await service.GetAllShipmentsAsync()));

        group.MapGet("/customer/{email}", async (string email, IShipmentService service) =>
            Results.Ok(await service.GetShipmentsForCustomerAsync(email)));

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        }).AllowAnonymous();

        group.MapPut("/{id:int}/status", async (int id, [FromBody] UpdateStatusRequest request, IShipmentService service) =>
        {
            var success = await service.UpdateShipmentStatusAsync(id, request.NewStatus);
            return success ? Results.NoContent() : Results.NotFound();
        });
    }
}

