@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Dispatcher")]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input class="form-control" placeholder="Filter by destination..." @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-primary w-100" @onclick="LoadShipments">
            <span class="bi bi-arrow-clockwise"></span> Refresh
        </button>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments match the current filter.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Customer</th>
                    <th>Status</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><strong>@s.TrackingNumber</strong></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.CustomerEmail</td>
                        <td><span class="badge @GetStatusBadge(s.Status)">@s.Status</span></td>
                        <td>@s.ShippedDate.ToString("MMM dd, yyyy")</td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm" value="@s.Status"
                                    @onchange="e => UpdateStatus(s, e)">
                                @foreach (var st in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@st">@st</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (!string.IsNullOrEmpty(message))
{
    <div class="alert @messageClass alert-dismissible mt-3" role="alert">
        @message
        <button type="button" class="btn-close" @onclick="() => message = null"></button>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private string? message;
    private string messageClass = "alert-success";

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter));

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var success = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            if (success)
            {
                shipment.Status = newStatus;
                message = $"Shipment {shipment.TrackingNumber} updated to {newStatus}.";
                messageClass = "alert-success";
            }
            else
            {
                message = $"Failed to update shipment {shipment.TrackingNumber}.";
                messageClass = "alert-danger";
            }
        }
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

