@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track a Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number (e.g., SHP-10001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@searching">
                @if (searching)
                {
                    <span class="spinner-border spinner-border-sm" role="status"></span>
                }
                else
                {
                    <span>Search</span>
                }
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedNumber</strong>. Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card" style="max-width: 600px;">
        <div class="card-header bg-primary text-white d-flex justify-content-between">
            <span>Tracking: <strong>@shipment.TrackingNumber</strong></span>
            <span class="badge @GetStatusBadge(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-5">Description</dt>
                <dd class="col-sm-7">@shipment.Description</dd>

                <dt class="col-sm-5">Origin</dt>
                <dd class="col-sm-7">@shipment.Origin</dd>

                <dt class="col-sm-5">Destination</dt>
                <dd class="col-sm-7">@shipment.Destination</dd>

                <dt class="col-sm-5">Shipped Date</dt>
                <dd class="col-sm-7">@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>

                <dt class="col-sm-5">Estimated Delivery</dt>
                <dd class="col-sm-7">
                    <strong class="@(shipment.EstimatedDelivery < DateTime.UtcNow && shipment.Status != ShipmentStatus.Delivered ? "text-danger" : "text-success")">
                        @shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")
                    </strong>
                </dd>
            </dl>
        </div>

        @{
            var progress = GetProgress(shipment.Status);
        }
        <div class="card-footer">
            <div class="progress" style="height: 25px;">
                <div class="progress-bar @(shipment.Status == ShipmentStatus.Delayed ? "bg-danger" : "bg-success")"
                     role="progressbar" style="width: @(progress)%"
                     aria-valuenow="@progress" aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool searched;
    private bool searching;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        searching = true;
        searched = false;
        shipment = null;

        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        searchedNumber = trackingNumber.Trim();
        searched = true;
        searching = false;
    }

    private static int GetProgress(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        _ => 0
    };

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}
